use youlai_boot;

-- 既存データを削除してから挿入（FK制約を考慮した順序）
DELETE FROM `retail_sales_detail` WHERE sales_id IN (SELECT id FROM `retail_sales` WHERE store_id BETWEEN 1 AND 30);
DELETE FROM `retail_sales` WHERE store_id BETWEEN 1 AND 30;
DELETE FROM `retail_alert` WHERE store_id BETWEEN 1 AND 30;
DELETE FROM `retail_inventory_transaction` WHERE store_id BETWEEN 1 AND 30;
DELETE FROM `retail_inventory` WHERE store_id BETWEEN 1 AND 30;
DELETE FROM `retail_device` WHERE store_id BETWEEN 1 AND 30;
DELETE FROM `retail_sales_summary` WHERE store_id BETWEEN 1 AND 30;
DELETE FROM `retail_sales_trend` WHERE store_id BETWEEN 1 AND 30;
DELETE FROM `retail_product` WHERE id BETWEEN 1 AND 45;
DELETE FROM `retail_store` WHERE id BETWEEN 1 AND 30;
DELETE FROM `retail_category` WHERE id BETWEEN 1 AND 38;

