-- ============================================================
-- TOP画面用追加データ
-- ============================================================

-- ----------------------------
-- 売上サマリーテーブル（TOP画面用）
-- ----------------------------
CREATE TABLE IF NOT EXISTS `retail_sales_summary` (
    `id` BIGINT AUTO_INCREMENT PRIMARY KEY,
    `store_id` BIGINT NOT NULL,
    `summary_date` DATE NOT NULL,
    `period_type` ENUM('DAILY', 'WEEKLY', 'MONTHLY') NOT NULL,
    `total_sales` DECIMAL(15,2) NOT NULL DEFAULT 0 COMMENT '売上高',
    `total_transactions` INT NOT NULL DEFAULT 0 COMMENT '取引件数',
    `total_items_sold` INT NOT NULL DEFAULT 0 COMMENT '販売商品数',
    `average_transaction_value` DECIMAL(10,2) COMMENT '平均客単価',
    `created_at` DATETIME DEFAULT CURRENT_TIMESTAMP,
    `updated_at` DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
    UNIQUE KEY `uk_sales_summary` (`store_id`, `summary_date`, `period_type`),
    KEY `idx_sales_summary_date` (`summary_date`, `period_type`),
    CONSTRAINT `fk_sales_summary_store` FOREIGN KEY (`store_id`) REFERENCES `retail_store`(`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='売上サマリー';

-- ----------------------------
-- 売上推移テーブル（TOP画面グラフ用）
-- ----------------------------
CREATE TABLE IF NOT EXISTS `retail_sales_trend` (
    `id` BIGINT AUTO_INCREMENT PRIMARY KEY,
    `store_id` BIGINT NOT NULL,
    `trend_month` DATE NOT NULL COMMENT '対象月（月初日）',
    `sales_amount` DECIMAL(15,2) NOT NULL DEFAULT 0 COMMENT '売上高',
    `is_forecast` BOOLEAN DEFAULT FALSE COMMENT '予測データフラグ',
    `growth_rate` DECIMAL(5,2) COMMENT '前月比成長率（%）',
    `created_at` DATETIME DEFAULT CURRENT_TIMESTAMP,
    `updated_at` DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
    UNIQUE KEY `uk_sales_trend` (`store_id`, `trend_month`),
    KEY `idx_sales_trend_month` (`trend_month`),
    CONSTRAINT `fk_sales_trend_store` FOREIGN KEY (`store_id`) REFERENCES `retail_store`(`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='売上推移';

